CREATE OR REPLACE FUNCTION get_master_diagnostics() RETURNS TABLE ( id UUID, user_id UUID, nome_pagamento TEXT, email_pagamento TEXT, idade TEXT, genero TEXT, cidade_estado_pais TEXT, renda_mensal TEXT, status_parental TEXT, estado_civil TEXT, escolaridade TEXT, status_proprietario TEXT, emprego_atual TEXT, como_conheceu TEXT, tempo_conhece TEXT, comprou_similar TEXT, influencia_compra TEXT, sobre_voce TEXT, objetivos TEXT, sonhos TEXT, dificuldades_medos TEXT, ferramenta_desejada TEXT, bonus_resgatado BOOLEAN, created_at TIMESTAMPTZ ) LANGUAGE plpgsql SECURITY DEFINER AS  BEGIN IF auth.jwt() ->> 'email' != 'hg.lavila@gmail.com' THEN RAISE EXCEPTION 'Acesso negado'; END IF; RETURN QUERY SELECT d.id, d.user_id, (u.raw_user_meta_data->->'full_name')::TEXT as nome_pagamento, u.email::TEXT as email_pagamento, d.idade, d.genero, d.cidade_estado_pais, d.renda_mensal, d.status_parental, d.estado_civil, d.escolaridade, d.status_proprietario, d.emprego_atual, d.como_conheceu, d.tempo_conhece, d.comprou_similar, d.influencia_compra, d.sobre_voce, d.objetivos, d.sonhos, d.dificuldades_medos, d.ferramenta_desejada, d.bonus_resgatado, d.created_at FROM public.pesquisa_diagnostico_clientes d JOIN auth.users u ON d.user_id = u.id ORDER BY d.created_at DESC; END; ; 
